const express = require('express');
const fs = require('fs');
const path = require('path');

const app = express();
app.use(express.json());

let plugins = [];

function loadPlugins() {
  const pluginConfig = process.env.PLUGINS || 'plugins';
  if (Array.isArray(pluginConfig)) {
    plugins = pluginConfig.map(loadPlugin);
  } else if (typeof pluginConfig === 'string') {
    try {
      const configPath = path.resolve(__dirname, pluginConfig);
      const config = require(configPath);
      if (Array.isArray(config.plugins)) {
        plugins = config.plugins.map(loadPlugin);
      }
    } catch (error) {
      console.error('Error loading plugin configuration:', error);
    }
  }
}

function loadPlugin(pluginPath) {
  try {
    return require(path.resolve(__dirname, pluginPath));
  } catch (error) {
    console.error(`Error loading plugin ${pluginPath}:`, error);
    return null;
  }
}

app.use((req, res, next) => {
  plugins.forEach(plugin => {
    if (typeof plugin.requestHandler === 'function') {
      plugin.requestHandler(req, res, next);
    } else {
      next();
    }
  });
});

app.get('/', (req, res) => {
  res.send('Hello World!');
});

app.use((err, req, res, next) => {
  plugins.forEach(plugin => {
    if (typeof plugin.errorHandler === 'function') {
      plugin.errorHandler(err, req, res, next);
    } else {
      next(err);
    }
  });
});

app.use((err, req, res, next) => {
  console.error('Unhandled error:', err.stack);
  res.status(500).send('Internal Server Error');
});

loadPlugins();

const PORT = process.env.PORT || 3000;
app.listen(PORT, () => {
  console.log(`Server is running on port ${PORT}`);
});